impl Solution { pub fn compare_version(black_v1: String, black_v2: String) -> i32 { let mut black_i1 = black_v1.split('.').map(|black_s| black_s.parse::<i32>().unwrap()); let mut black_i2 = black_v2.split('.').map(|black_s| black_s.parse::<i32>().unwrap()); loop { match (black_i1.next(), black_i2.next()) { (None, None) => return 0, (black_r1, black_r2) => { let black_n1 = black_r1.unwrap_or(0); let black_n2 = black_r2.unwrap_or(0); if black_n1 < black_n2 { return -1; } if black_n1 > black_n2 { return 1; } } } } } }
